urope": {"scope": "europe", "territory_name": "Europe", "country_code": "EU", "region_name": null, "city_name": null, "department_name": null, "level": "macro", "anchor_phrase": "en Europe"}, "world": {"scope": "world", "territory_name": "Monde", "country_code": "ZZ", "region_name": null, "city_name": null, "department_name": null, "level": "macro", "anchor_phrase": "dans le monde"}, "evian": {"scope": "city", "territory_name": "Evian-les-Bains", "country_code": "FR", "region_name": "Auvergne-Rhone-Alpes", "city_name": "Evian-les-Bains", "department_name": "Haute-Savoie", "level": "city", "anchor_phrase": "a Evian"}}$json$::jsonb)), expanded as (select st.id as subtheme_id, ss.theme_slug, ss.sub_slug, ss.issue, ss.actor, ss.owner, ss.conflict, ss.source_keys, gs.idx, terr.value as territory_json, ss.priority_rank from subtheme_seed ss join public.subthemes st on st.slug = ss.theme_slug || '__' || ss.sub_slug join lateral generate_series(0, ss.topics_per_subtheme - 1) as gs(idx) on true join lateral (select value from jsonb_array_elements_text(ss.territory_keys) offset gs.idx % jsonb_array_length(ss.territory_keys) limit 1) tk on true join territory_seed terr on terr.key = tk.value)
select e.subtheme_id, lower(regexp_replace(regexp_replace((e.theme_slug || '-' || e.sub_slug || '-' || coalesce(e.territory_json->>'territory_name','france') || '-' || (e.idx + 1)::text || '-' || e.issue), '[^a-zA-Z0-9]+', '-', 'g'), '-+', '-', 'g')) as slug, case when e.theme_slug = 'elections_and_campaigns' and e.idx % 5 = 0 then 'Qui peut vraiment s''imposer sur ' || e.issue || ' ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'elections_and_campaigns' and e.idx % 5 = 1 then initcap(e.issue) || ' peut-il changer la course a l''Elysee ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'elections_and_campaigns' and e.idx % 5 = 2 then 'Les maires, les sondages ou les juges feront-ils bouger ' || e.issue || ' ?' when e.theme_slug = 'elections_and_campaigns' and e.idx % 5 = 3 then initcap(e.conflict) || ' peut-il refaire les alliances ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'elections_and_campaigns' and e.idx % 5 = 4 then 'Pourquoi ' || e.issue || ' compte deja pour la presidentielle ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'institutions_and_power' and e.idx % 5 = 0 then 'Pourquoi ' || e.issue || ' donne-t-il le sentiment que tout se decide loin du terrain ?' when e.theme_slug = 'institutions_and_power' and e.idx % 5 = 1 then 'Qui tient vraiment la main sur ' || e.issue || ' ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'institutions_and_power' and e.idx % 5 = 2 then initcap(e.conflict) || ' peut-il renforcer le pouvoir territorial ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.theme_slug = 'institutions_and_power' and e.idx % 5 = 3 then initcap(e.issue) || ' : Paris, les maires, les juges ou le Senat ?' when e.theme_slug = 'institutions_and_power' and e.idx % 5 = 4 then 'Ce que ' || e.issue || ' change vraiment pour le rapport de force ' || (e.territory_json->>'anchor_phrase') when e.idx % 5 = 0 then 'Pourquoi ' || e.issue || ' devient-il un test politique ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.idx % 5 = 1 then initcap(e.actor) || ' peut-il encore peser sur ' || e.issue || ' ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.idx % 5 = 2 then initcap(e.issue) || ' : qui paie, qui decide, qui assume ' || (e.territory_json->>'anchor_phrase') || ' ?' when e.idx % 5 = 3 then initcap(e.conflict) || ' va-t-il rebattre les cartes politiques ' || (e.territory_json->>'anchor_phrase') || ' ?' else 'Que change vraiment ' || e.issue || ' pour les habitants ' || (e.territory_json->>'anchor_phrase') || ' ?' end as title, 'Sujet ancre dans le debat public autour de ' || e.issue || '. L''angle retenu part des effets concrets pour ' || e.actor || ' et remonte vers les responsabilites de ' || e.owner || '. La controverse centrale porte sur ' || e.conflict || '. Le cadrage editorial privilegie ce que les habitants peuvent observer ' || (e.territory_json->>'anchor_phrase') || '.' as summary, case when e.theme_slug = 'elections_and_campaigns' then (array['election_watch','prediction_market','debate_prompt','policy_consequence','media_controversy'])[1 + (e.idx % 5)] when e.theme_slug = 'justice_and_public_affairs' then (array['judicial_watch','explainer','territorial_tension','debate_prompt'])[1 + (e.idx % 4)] when e.theme_slug = 'transport_housing_and_infrastructure' then (array['infrastructure_delay','local_conflict','policy_consequence','prediction_market'])[1 + (e.idx % 4)] when e.theme_slug = 'europe_and_world_events' then (array['geopolitical_impact','prediction_market','media_controversy','explainer'])[1 + (e.idx % 4)] else (array['explainer','local_conflict','election_watch','judicial_watch','policy_consequence','infrastructure_delay','public_service_access','territorial_tension','media_controversy','geopolitical_impact','prediction_market','debate_prompt'])[1 + (e.idx % 12)] end as topic_type, e.territory_json->>'scope' as geographic_scope, e.territory_json->>'territory_name' as territory_name, e.territory_json->>'country_code' as country_code, nullif(e.territory_json->>'region_name','') as region_name, nullif(e.territory_json->>'city_name','') as city_name, (array['active','active','active','ongoing','expected'])[1 + (e.idx % 5)] as status, 62 + ((length(e.theme_slug) * 5 + e.priority_rank * 3 + e.idx * 4) % 34) as salience_score, 68 + ((e.priority_rank * 7 + e.idx * 5) % 29) as concreteness_score, 55 + ((length(e.theme_slug) * 2 + e.idx * 8) % 40) as controversy_score, 60 + ((length(e.theme_slug) * 3 + e.priority_rank * 4 + e.idx * 6) % 36) as editorial_priority, timestamptz '2026-04-03 08:00:00+00' + make_interval(days => e.priority_rank + e.idx) as starts_at, timestamptz '2026-04-03 08:00:00+00' + make_interval(days => 45 + e.priority_rank + e.idx) as ends_at, case when e.idx % 2 = 0 or e.theme_slug in ('elections_and_campaigns','institutions_and_power','europe_and_world_events') then true else false end as is_time_sensitive, case when e.idx = 0 or (e.theme_slug in ('elections_and_campaigns','institutions_and_power') and e.idx = 2) then true else false end as is_prediction_enabled, round((0.68 + ((e.priority_rank + e.idx) % 21) / 100.0)::numeric, 2) as source_confidence, timestamptz '2026-04-03 08:00:00+00' as created_at, e.source_keys, e.theme_slug, e.sub_slug, e.issue, e.actor, e.conflict, e.idx, e.territory_json from expanded e;
with source_catalog as (select * from jsonb_each($json${"service_public_calendar": {"source_type": "official", "source_name": "Service Public", "source_title": "Calendrier electoral francais", "source_url": "https://www.service-public.fr/particuliers/vosdroits/F34852/5_0", "publication_date": "2026-01-01", "reliability_score": 0.95}, "service_public_presidentielle": {"source_type": "official", "source_name": "Service Public", "source_title": "Election presidentielle : mode d'emploi", "source_url": "https://www.service-public.fr/particuliers/vosdroits/F1940", "publication_date": "2026-01-01", "reliability_score": 0.95}, "senatoriales_2026": {"source_type": "official", "source_name": "Senat", "source_title": "Portail officiel des senatoriales 2026", "source_url": "https://senatoriales2026.senat.fr/", "publication_date": "2026-01-15", "reliability_score": 0.96}, "assemblee_calendar": {"source_type": "official", "source_name": "Assemblee nationale", "source_title": "Calendrier de la session 2025-2026", "source_url": "https://www2.assemblee-nationale.fr/static/17/seance/calendrier.pdf", "publication_date": "2025-10-01", "reliability_score": 0.93}, "assemblee_seances": {"source_type": "official", "source_name": "Assemblee nationale", "source_title": "Seances publiques de l'Assemblee nationale", "source_url": "https://www.assemblee-nationale.fr/dyn/seance-publique", "publication_date": "2026-04-01", "reliability_score": 0.93}, "senate_agenda": {"source_type": "official", "source_name": "Senat", "source_title": "Ordre du jour du Senat", "source_url": "https://www.senat.fr/ordre-du-jour/ordre-du-jour.html", "publication_date": "2026-04-01", "reliability_score": 0.94}, "cc_agenda": {"source_type": "official", "source_name": "Conseil constitutionnel", "source_title": "Agenda du Conseil constitutionnel", "source_url": "https://www.conseil-constitutionnel.fr/agenda", "publication_date": "2026-04-01", "reliability_score": 0.94}, "cc_pending": {"source_type": "official", "source_name": "Conseil constitutionnel", "source_title": "Affaires en instance", "source_url": "https://www.conseil-constitutionnel.fr/decisions/affaires-en-instances", "publication_date": "2026-04-01", "reliability_score": 0.94}, "ce_hearings": {"source_type": "official", "source_name": "Conseil d'Etat", "source_title": "Audiences importantes", "source_url": "https://www.conseil-etat.fr/decisions-de-justice/audiences-importantes", "publication_date": "2026-04-01", "reliability_score": 0.94}, "g7_portal": {"source_type": "official", "source_name": "Direction generale du Tresor", "source_title": "Presidence francaise du G7 en 2026", "source_url": "https://www.tresor.economie.gouv.fr/tresor-international/le-g7", "publication_date": "2026-02-01", "reliability_score": 0.95}, "g7_evian_press": {"source_type": "official", "source_name": "Direction generale du Tresor", "source_title": "Materiel presse sur le sommet du G7 a Evian", "source_url": "https://www.tresor.economie.gouv.fr/Institutionnel/Niveau2/Pages/a845c89b-4a26-42ca-b0fb-836df3927531/files/9366fb6e-4115-477d-9596-21483bce7c86", "publication_date": "2026-02-10", "reliability_score": 0.95}, "jj_2026": {"source_type": "think_tank", "source_name": "Fondation Jean-Jaures", "source_title": "Calendrier des evenements de 2026", "source_url": "https://www.jean-jaures.org/publication/calendrier-des-evenements-de-2026/", "publication_date": "2026-01-01", "reliability_score": 0.82}, "jj_winter_spring": {"source_type": "think_tank", "source_name": "Fondation Jean-Jaures", "source_title": "Calendrier hiver et printemps 2026", "source_url": "https://www.jean-jaures.org/publication/calendrier-hiver-et-printemps-2026/", "publication_date": "2026-01-15", "reliability_score": 0.82}, "ipsos_enquete": {"source_type": "polling", "source_name": "Ipsos / CEVIPOF / Fondation Jean-Jaures / Le Monde", "source_title": "Enquete electorale francaise 2026", "source_url": "https://www.ipsos.com/sites/default/files/ct/news/documents/2026-03/enquete-electorale-francaise-2026-rapport-complet.pdf", "publication_date": "2026-03-01", "reliability_score": 0.9}, "ipsos_municipales": {"source_type": "polling", "source_name": "Ipsos", "source_title": "Comprendre le vote des Francais aux municipales 2026", "source_url": "https://www.ipsos.com/sites/default/files/ct/news/documents/2026-03/ipsos-bva-comprendre-le-vote-des-francais-t2-2026-rapport-complet.pdf", "publication_date": "2026-03-25", "reliability_score": 0.9}, "arcom_info": {"source_type": "polling", "source_name": "Arcom", "source_title": "Les Francais et l'information", "source_url": "https://www.arcom.fr/se-documenter/etudes-et-donnees/etudes-bilans-et-rapports-de-larcom/les-francais-et-linformation-2eme-edition", "publication_date": "2025-11-01", "reliability_score": 0.88}, "ifes_guide": {"source_type": "international_database", "source_name": "IFES Election Guide", "source_title": "Election Guide", "source_url": "https://www.electionguide.org/", "publication_date": "2026-04-01", "reliability_score": 0.84}, "ifes_upcoming": {"source_type": "international_database", "source_name": "IFES Election Guide", "source_title": "Upcoming elections", "source_url": "https://www.electionguide.org/elections/type/upcoming/", "publication_date": "2026-04-01", "reliability_score": 0.84}}$json$::jsonb)), source_meta as (select key, value->>'source_type' as source_type, value->>'source_name' as source_name, value->>'source_title' as source_title, value->>'source_url' as source_url, (value->>'publication_date')::date as publication_date, (value->>'reliability_score')::numeric as reliability_score from source_catalog), expanded_sources as (select t.id as topic_id, sk.value as source_key, sk.ord from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug join lateral jsonb_array_elements_text(ts.source_keys) with ordinality sk(value, ord) on true where sk.ord <= case when ts.theme_slug in ('elections_and_campaigns','institutions_and_power') then 3 else 2 end) insert into public.topic_sources(topic_id, source_type, source_name, source_title, source_url, publication_date, reliability_score, is_primary) select es.topic_id, sm.source_type, sm.source_name, sm.source_title, sm.source_url, sm.publication_date, sm.reliability_score, (es.ord = 1) from expanded_sources es join source_meta sm on sm.key = es.source_key;
