insert into public.themes(slug, name, description, priority_rank, is_active) select slug, name, description, priority_rank, true from theme_seed;
insert into public.subthemes(theme_id, slug, name, description, priority_rank, is_active) select t.id, ss.theme_slug || '__' || ss.sub_slug, ss.sub_name, ss.issue, ss.priority_rank, true from subtheme_seed ss join public.themes t on t.slug = ss.theme_slug;
insert into public.topics_editorial(subtheme_id, slug, title, summary, topic_type, geographic_scope, territory_name, country_code, region_name, city_name, status, salience_score, concreteness_score, controversy_score, editorial_priority, starts_at, ends_at, is_time_sensitive, is_prediction_enabled, source_confidence, created_at) select subtheme_id, slug, title, summary, topic_type, geographic_scope, territory_name, country_code, region_name, city_name, status, salience_score, concreteness_score, controversy_score, editorial_priority, starts_at, ends_at, is_time_sensitive, is_prediction_enabled, source_confidence, created_at from tmp_editorial_seed;
insert into public.topic_tags(topic_id, tag) select t.id, tag from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug join lateral unnest(array[ts.theme_slug, ts.sub_slug, ts.geographic_scope, lower(regexp_replace(ts.issue, '[^a-zA-Z0-9]+', '-', 'g')), case when ts.theme_slug in ('elections_and_campaigns','institutions_and_power') and (ts.issue like '%presidentielle%' or ts.title like '%Elysee%') then 'presidentielle-2027' when ts.theme_slug in ('elections_and_campaigns','institutions_and_power') then 'senatoriales-2026' else null end]) as tag on tag is not null;
insert into public.topic_territories(topic_id, territory_level, territory_name, country_code, region_name, department_name, city_name, is_primary) select t.id, ts.territory_json->>'level', ts.territory_name, ts.country_code, ts.region_name, ts.territory_json->>'department_name', ts.city_name, true from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug;
insert into public.topic_territories(topic_id, territory_level, territory_name, country_code, region_name, department_name, city_name, is_primary) select t.id, 'country', 'France', 'FR', null, null, null, false from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug where ts.territory_name <> 'France';
insert into public.prediction_questions_editorial(topic_id, question, prediction_type, resolution_criteria, resolution_source_url, closes_at) select t.id, case when row_number() over (order by t.id) % 4 = 1 then 'Une annonce officielle majeure sur ' || ts.issue || ' interviendra-t-elle avant la cloture du sujet ?' when row_number() over (order by t.id) % 4 = 2 then initcap(ts.issue) || ' dominera-t-il le debat politique pendant au moins une semaine ?' when row_number() over (order by t.id) % 4 = 3 then 'Une decision institutionnelle visible changera-t-elle la donne sur ' || ts.issue || ' ?' else 'Le rapport de force public sur ' || ts.issue || ' basculera-t-il ' || (ts.territory_json->>'anchor_phrase') || ' ?' end, 'prediction_market', case when row_number() over (order by t.id) % 4 = 1 then 'Resolution Oui si une annonce publique explicite concernant le sujet est publiee avant la date de cloture.' when row_number() over (order by t.id) % 4 = 2 then 'Resolution Oui si la sequence publique documentee par la source de resolution reste centree sur ce sujet pendant une semaine consecutive.' when row_number() over (order by t.id) % 4 = 3 then 'Resolution Oui si une decision officielle modifie clairement le cadre politique ou administratif du sujet.' else 'Resolution Oui si un resultat, vote, sondage ou arbitrage officialise un changement net de rapport de force sur ce sujet.' end, ps.source_url, least(ts.ends_at - interval '4 days', ts.starts_at + interval '60 days') from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug join lateral (select source_url from public.topic_sources s where s.topic_id = t.id and s.is_primary order by s.id limit 1) ps on true where ts.is_prediction_enabled;
insert into public.discussion_prompts(topic_id, prompt, prompt_type, tone) select t.id, case when ts.idx % 4 = 0 then 'Dans votre experience, qui a vraiment la main sur ' || ts.issue || ' ' || (ts.territory_json->>'anchor_phrase') || ' ?' when ts.idx % 4 = 1 then 'Est-ce que ' || ts.actor || ' paient le prix politique de ' || ts.conflict || ' ?' when ts.idx % 4 = 2 then 'Pourquoi ' || ts.issue || ' parait-il si lent a bouger ' || (ts.territory_json->>'anchor_phrase') || ' ?' else 'Faut-il juger ' || ts.issue || ' d''abord a ses effets concrets plutot qu''aux discours ?' end, case when ts.idx % 4 = 0 then 'responsibility' when ts.idx % 4 = 1 then 'fairness' when ts.idx % 4 = 2 then 'lived_experience' else 'priority' end, case when ts.idx % 4 = 0 then 'direct' when ts.idx % 4 = 1 then 'argumentative' when ts.idx % 4 = 2 then 'grounded' else 'calm' end from tmp_editorial_seed ts join public.topics_editorial t on t.slug = ts.slug where ts.idx < 2;
